 Here's a JavaScript function that checks if an input number from an given array is prime, and prints it to the console if it is. This function then, when provided with an array of five numbers, will identify and output any prime numbers.

```javascript
function isPrime(num) {
  // Edge cases: 0, 1, and negative numbers are not prime
  if (num <= 1) return false;

  // Up to the square root of the number, check for divisibility
  for (let i = 2; i <= Math.sqrt(num); i++) {
    if (num % i === 0) return false;
  }

  // If no divisors found up to the square root, the number is prime
  return true;
}

function checkPrimesInArray(arr) {
  if (arr.length !== 5) {
    throw new Error("Input array must contain exactly five numbers");
  }

  for (let num of arr) {
    const isThisNumberPrime = isPrime(num);
    if (isThisNumberPrime) {
      console.log(num);
    }
  }
}
```

Use the `checkPrimesInArray` function with an array of five numbers as its argument:
```javascript
checkPrimesInArray([3, 6, 11, 7, 17]); // Output: 11, 7, 17 (assuming the console supports multiple lines)
```

